import{_ as t,o,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"23. Termination Of Employment","description":"","frontmatter":{"title":"23. Termination Of Employment","eba":"Biomedical Engineers 2025-2028","topics":["employment","termination"]},"headers":[],"relativePath":"ebas/biomedical-engineers/employment/23-termination-of-employment.md","filePath":"ebas/biomedical-engineers/employment/23-termination-of-employment.md"}'),a={name:"ebas/biomedical-engineers/employment/23-termination-of-employment.md"};function r(m,e,l,p,s,c){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_23-termination-of-employment" tabindex="-1">23. Termination Of Employment <a class="header-anchor" href="#_23-termination-of-employment" aria-label="Permalink to &quot;23. Termination Of Employment&quot;">​</a></h1><p>This clause only applies to full-time and part-time Employees.</p><p><strong>23.1</strong> Notice of Termination by Employer</p><p><strong>(a)</strong> An Employer may terminate the employment of an Employee by providing four weeks&#39; notice in writing.</p><p><strong>(b)</strong> The notice required will be increased by one week if the Employee is over 45 years of age and has completed at least two years of continuous service.</p><p><strong>(c)</strong> An Employer may make payment in lieu of notice for part or all of the notice period. The payment in lieu of notice must equal or exceed the total of all amounts that the Employer would have paid had the Employee’s employment continued until the end of the required notice period, including superannuation. That payment must be calculated on the basis of:</p><p><strong>(i)</strong> the Employee’s ordinary hours of work (even if not standard hours);</p><p><strong>(ii)</strong> the amounts ordinarily payable to the Employee in respect of those hours, including (for example) allowances, loading and penalties; and</p><p><strong>(iii)</strong> any other amounts payable under the Employee&#39;s contract of employment.</p><p><strong>(d)</strong> Subclauses 23.1(a) 23.1(b) and 23.1(c) do not affect an Employer&#39;s right to terminate an Employee&#39;s employment without notice for serious misconduct (as defined for the purposes of the Act).</p><p><strong>(e)</strong> Time off work during notice period Where an Employer has given notice of termination to an Employee, an Employee will be allowed up to one day’s time off without loss of pay for the purpose of seeking other employment. The time off shall be taken at times that are convenient to the Employee after consultation with the Employer.</p><p><strong>23.2</strong> Notice of Termination by Employee An Employee may terminate their employment by providing four weeks’ notice to the Employer in writing.</p><p><strong>23.3</strong> Certificate of Service on Termination A certificate of service including the information at <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a> will be provided to the Employee wherever practicable within 21 days of the date of termination including where a full-time or part-time Employee terminates employment and becomes a casual Employee.</p><p>Plain language terms: resignation, dismissal.</p>',14)])])}const y=t(a,[["render",r]]);export{d as __pageData,y as default};
